#include "ina260.h"
#include <Wire.h>
#include <Adafruit_INA260.h>
static Adafruit_INA260 ina;
static float _mA=0,_v=0,_mW=0;
static unsigned long _last=0;
void ina260_setup(){Wire.begin();if(!ina.begin()){Serial.println("[ina260] Fail!");return;}Serial.println("[ina260] OK");}
void ina260_loop(){if(millis()-_last<500)return;_last=millis();_mA=ina.readCurrent();_v=ina.readBusVoltage()/1000.0;_mW=ina.readPower();}
float ina260_get_current_mA(){return _mA;}
float ina260_get_voltage(){return _v;}
float ina260_get_power_mW(){return _mW;}
